const cpuData = $('قراءة CPU الكلي').first().json;
const memData = $('قراءة الذاكرة الكلية').first().json;

const cpu = cpuData?.data?.result?.[0]?.value?.[1]
  ? parseFloat(cpuData.data.result[0].value[1])
  : 0;

const memory = memData?.data?.result?.[0]?.value?.[1]
  ? parseFloat(memData.data.result[0].value[1])
  : 0;

let status = 'normal';
let action = 'none';
let message = '';

if (cpu > 80) {
  status = 'critical';
  action = 'defer_tasks';
  message = `تحذير: CPU مرتفع جداً (${cpu.toFixed(1)}%) - سيتم تأجيل المهام الثقيلة`;
} else if (cpu > 60) {
  status = 'warning';
  action = 'monitor';
  message = `تنبيه: CPU مرتفع (${cpu.toFixed(1)}%) - المراقبة مستمرة`;
} else if (cpu < 20) {
  status = 'low';
  action = 'advance_tasks';
  message = `الموارد متاحة: CPU منخفض (${cpu.toFixed(1)}%) - يمكن تقديم المهام المؤجلة`;
} else {
  status = 'normal';
  action = 'none';
  message = `النظام يعمل بشكل طبيعي - CPU: ${cpu.toFixed(1)}%`;
}

return [{
  json: {
    cpu: cpu.toFixed(2),
    memory_mb: memory.toFixed(0),
    status,
    action,
    message,
    timestamp: new Date().toISOString()
  }
}];

const metrics = $('تحليل المقاييس').first().json;
const ollamaResponse = $('توصية Ollama').first().json;

const advice = ollamaResponse?.response || 'لا توجد توصية';

return [{
  json: {
    ...metrics,
    ollama_advice: advice.trim(),
    log_entry: `[${metrics.timestamp}] CPU:${metrics.cpu}% MEM:${metrics.memory_mb}MB STATUS:${metrics.status} | ${advice.trim()}`
  }
}];

// تسجيل قرار التأجيل
const data = $input.first().json;
console.log(`🔴 HIGH LOAD - Deferring tasks: CPU=${data.cpu}%`);
console.log(`Ollama advice: ${data.ollama_advice}`);

return [{
