// تسجيل الحالة الطبيعية
const data = $input.first().json;
console.log(`✅ NORMAL: CPU=${data.cpu}% | ${data.message}`);

return [{
  json: {
    action_taken: 'monitoring',
    status: data.status,
    cpu: data.cpu,
    memory_mb: data.memory_mb,
    advice: data.ollama_advice,
    timestamp: data.timestamp
  }
}];
